// JSON 时间字符串先还原成 Date；先让 overview 完成异步 scale 初始化,再设置 data,避免其 domainRange 抢跑
import TimelinesChart from 'https://cdn.jsdelivr.net/npm/timelines-chart@2/+esm';
const el = document.getElementById('timelines'); el.style.height = `${spec.height ?? 480}px`;
const o = data.options ?? {};
const groups = (data.groups ?? []).map(group => ({ ...group, data: (group.data ?? []).map(row => ({ ...row, data: (row.data ?? []).map(segment => ({ ...segment, timeRange: segment.timeRange.map(value => value instanceof Date ? value : new Date(value)) })) })) }));
const chart = new TimelinesChart(el).width(el.clientWidth || 600).maxHeight(spec.height ?? 480).maxLineHeight(o.max_line_height ?? 12);
chart.zQualitative(o.qualitative ?? false).useUtc(o.use_utc ?? false).timeFormat(o.time_format ?? '%Y-%m-%d %-I:%M:%S %p').enableOverview(o.enable_overview ?? true);
await new Promise(ok => setTimeout(ok, 100)); chart.data(groups);

